const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };


const response = $input.first().json;

if (response.error) {
  throw new Error('OpenAI API error: ' + response.error.message);
}

if (!response.choices || response.choices.length === 0) {
  throw new Error('No choices returned: ' + JSON.stringify(response).slice(0, 300));
}

const raw = response.choices[0].message.content;
const clean = raw.replace(/```json|```/gi, '').trim();

let parsed;
try {
  parsed = JSON.parse(clean);
} catch(e) {
  throw new Error('JSON parse failed: ' + raw.slice(0, 300));
}

// Schema validation
const requiredFields = ['rag_status', 'days_variance', 'blockers', 'velocity_trend', 'summary'];
const missing = requiredFields.filter(f => parsed[f] === undefined || parsed[f] === null);
if (missing.length > 0) {
  throw new Error(
    'OpenAI response missing required fields: ' + missing.join(', ') +
    '\nRaw response: ' + raw.slice(0, 300)
  );
}

const validRag = ['red', 'amber', 'green'];
if (!validRag.includes(parsed.rag_status.toLowerCase())) {
  throw new Error(
    'Invalid rag_status value: ' + parsed.rag_status +
    '. Must be one of: ' + validRag.join(', ')
  );
}

if (!Array.isArray(parsed.blockers)) {
  throw new Error('blockers must be an array, got: ' + typeof parsed.blockers);
}

parsed.workstream = $('Execute Workflow Trigger').first().json.workstream;
parsed.jiraKey    = $('Execute Workflow Trigger').first().json.jiraKey;
parsed.as_of      = new Date().toISOString();

log(
  'Status parsed for', parsed.workstream,
  '| RAG:', parsed.rag_status,
  '| Blockers:', parsed.blockers.length,
  '| Velocity:', parsed.velocity_trend
);

return [{ json: parsed }];

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };


const item = $input.first().json;

const workstream = item.workstream;
const jiraKey    = item.jiraKey;
const priority   = item.priority;

// Validate jiraKey is present
if (!jiraKey || typeof jiraKey !== 'string') {
  throw new Error(
    'Validation failed: jiraKey is missing or not a string.' +
    '\nReceived: ' + JSON.stringify(item)
  );
}

// Validate jiraKey format — must be 2-10 uppercase letters
// optionally followed by a hyphen (e.g. PROJ, MYAPP, TEAM-)
const jiraKeyPattern = /^[A-Z][A-Z0-9]{1,9}-?$/;
if (!jiraKeyPattern.test(jiraKey.trim())) {
  throw new Error(
    'Validation failed: jiraKey "' + jiraKey + '" does not match expected format.' +
    '\nExpected pattern: 2-10 uppercase letters/numbers (e.g. PROJ, MYAPP).' +
    '\nThis is likely an LLM hallucination — check the orchestrator output.'
  );
}

// Validate workstream is present
if (!workstream || typeof workstream !== 'string' || workstream.trim() === '') {
  throw new Error(
    'Validation failed: workstream is missing or empty.' +
    '\nReceived: ' + JSON.stringify(item)
  );
}

// Validate priority is one of the expected values
const validPriorities = ['high', 'medium', 'low'];
if (priority && !validPriorities.includes(priority.toLowerCase())) {
  // Warn only — priority is not used in the JQL so not worth aborting for
  warn('Unexpected priority value: ' + priority + '. Continuing.');
}

// Pass through cleaned data
return [{
  json: {
    workstream: workstream.trim(),
    jiraKey:    jiraKey.trim().replace(/-$/, ''), // strip trailing hyphen if present
    priority:   priority ?? 'medium'
  }
}];

const DEBUG = $env.DEBUG === 'true';
const log   = (...args) => { if (DEBUG) console.log(...args); };
const warn  = (...args) => { if (DEBUG) console.log('[WARN]', ...args); };


const trigger = $('Execute Workflow Trigger').first().json;

warn(
  'No open sprint tickets found for workstream: ' + trigger.workstream +
  ' (jiraKey: ' + trigger.jiraKey + '). Returning default no-data status record.'
);

return [{
  json: {
    rag_status:      'amber',
    days_variance:   0,
    blockers:        [],
    velocity_trend:  'stable',
    summary:         'No open sprint data available for this workstream. Status could not be assessed this week.',
    workstream:      trigger.workstream,
    jiraKey:         trigger.jiraKey,
    as_of:           new Date().toISOString(),
    _no_data:        true
  }
}];
